#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define AMB_TEMP 80.0f

inline float hotspot_update(const __local float *src,
                            const __global float *power,
                            int x, int y, int col, int row,
                            int lx, int ly,
                            float Cap_1, float Rx_1, float Ry_1, float Rz_1)
{
    const int g = y * col + x;
    const int l = ly * BLOCK_SIZE + lx;
    const float center = src[l];
    float delta;

    if ((y == 0) && (x == 0)) {
        delta = Cap_1 * (power[0] +
                         (src[ly * BLOCK_SIZE + (lx + 1)] - center) * Rx_1 +
                         (src[(ly + 1) * BLOCK_SIZE + lx] - center) * Ry_1 +
                         (AMB_TEMP - center) * Rz_1);
    } else if ((y == 0) && (x == col - 1)) {
        delta = Cap_1 * (power[x] +
                         (src[ly * BLOCK_SIZE + (lx - 1)] - center) * Rx_1 +
                         (src[(ly + 1) * BLOCK_SIZE + lx] - center) * Ry_1 +
                         (AMB_TEMP - center) * Rz_1);
    } else if ((y == row - 1) && (x == col - 1)) {
        delta = Cap_1 * (power[g] +
                         (src[ly * BLOCK_SIZE + (lx - 1)] - center) * Rx_1 +
                         (src[(ly - 1) * BLOCK_SIZE + lx] - center) * Ry_1 +
                         (AMB_TEMP - center) * Rz_1);
    } else if ((y == row - 1) && (x == 0)) {
        delta = Cap_1 * (power[g] +
                         (src[ly * BLOCK_SIZE + (lx + 1)] - center) * Rx_1 +
                         (src[(ly - 1) * BLOCK_SIZE + lx] - center) * Ry_1 +
                         (AMB_TEMP - center) * Rz_1);
    } else if (y == 0) {
        delta = Cap_1 * (power[x] +
                         (src[ly * BLOCK_SIZE + (lx + 1)] +
                          src[ly * BLOCK_SIZE + (lx - 1)] -
                          2.0f * center) * Rx_1 +
                         (src[(ly + 1) * BLOCK_SIZE + lx] - center) * Ry_1 +
                         (AMB_TEMP - center) * Rz_1);
    } else if (x == col - 1) {
        delta = Cap_1 * (power[g] +
                         (src[(ly + 1) * BLOCK_SIZE + lx] +
                          src[(ly - 1) * BLOCK_SIZE + lx] -
                          2.0f * center) * Ry_1 +
                         (src[ly * BLOCK_SIZE + (lx - 1)] - center) * Rx_1 +
                         (AMB_TEMP - center) * Rz_1);
    } else if (y == row - 1) {
        delta = Cap_1 * (power[g] +
                         (src[ly * BLOCK_SIZE + (lx + 1)] +
                          src[ly * BLOCK_SIZE + (lx - 1)] -
                          2.0f * center) * Rx_1 +
                         (src[(ly - 1) * BLOCK_SIZE + lx] - center) * Ry_1 +
                         (AMB_TEMP - center) * Rz_1);
    } else if (x == 0) {
        delta = Cap_1 * (power[g] +
                         (src[(ly + 1) * BLOCK_SIZE + lx] +
                          src[(ly - 1) * BLOCK_SIZE + lx] -
                          2.0f * center) * Ry_1 +
                         (src[ly * BLOCK_SIZE + (lx + 1)] - center) * Rx_1 +
                         (AMB_TEMP - center) * Rz_1);
    } else {
        delta = Cap_1 * (power[g] +
                         (src[(ly + 1) * BLOCK_SIZE + lx] +
                          src[(ly - 1) * BLOCK_SIZE + lx] -
                          2.0f * center) * Ry_1 +
                         (src[ly * BLOCK_SIZE + (lx + 1)] +
                          src[ly * BLOCK_SIZE + (lx - 1)] -
                          2.0f * center) * Rx_1 +
                         (AMB_TEMP - center) * Rz_1);
    }

    return center + delta;
}

__kernel void hotspot(int iteration,
                      __global float *power,
                      __global float *temp_src,
                      __global float *temp_dst,
                      int col,
                      int row,
                      int borderCols,
                      int borderRows,
                      float Cap,
                      float Rx,
                      float Ry,
                      float Rz,
                      float step)
{
    const int tx = (int)get_local_id(0);
    const int ty = (int)get_local_id(1);
    const int bx = (int)get_group_id(0);
    const int by = (int)get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - (borderCols << 1);
    const int small_block_rows = BLOCK_SIZE - (borderRows << 1);

    const int x = bx * small_block_cols + tx - borderCols;
    const int y = by * small_block_rows + ty - borderRows;
    const int lidx = ty * BLOCK_SIZE + tx;

    __local float local_a[BLOCK_SIZE * BLOCK_SIZE];
    __local float local_b[BLOCK_SIZE * BLOCK_SIZE];

    __local float *src = local_a;
    __local float *dst = local_b;

    if (x >= 0 && x < col && y >= 0 && y < row) {
        src[lidx] = temp_src[y * col + x];
    } else {
        src[lidx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    const float Cap_1 = step / Cap;
    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;

    for (int i = 0; i < iteration; i++) {
        if (x >= 0 && x < col &&
            y >= 0 && y < row &&
            tx > i && tx < (BLOCK_SIZE - i - 1) &&
            ty > i && ty < (BLOCK_SIZE - i - 1)) {
            dst[lidx] = hotspot_update(src, power, x, y, col, row, tx, ty,
                                       Cap_1, Rx_1, Ry_1, Rz_1);
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (i != iteration - 1) {
            __local float *tmp = src;
            src = dst;
            dst = tmp;
        }
    }

    if (x >= 0 && x < col &&
        y >= 0 && y < row &&
        tx >= borderCols && tx < (BLOCK_SIZE - borderCols) &&
        ty >= borderRows && ty < (BLOCK_SIZE - borderRows)) {
        temp_dst[y * col + x] = dst[lidx];
    }
}
